#:property AllowUnsafeBlocks=true

Console.WriteLine("Testing stackalloc Span<nint> and Span<nuint>...");

Span<nint> signedSpan = stackalloc nint[4];
signedSpan[0] = 10;
signedSpan[1] = 20;
signedSpan[2] = 30;
signedSpan[3] = nint.MaxValue;

Console.WriteLine($"Span<nint> length: {signedSpan.Length}");
for (int i = 0; i < signedSpan.Length; i++)
    Console.WriteLine($"  signedSpan[{i}] = {signedSpan[i]}");

Span<nuint> unsignedSpan = stackalloc nuint[3];
unsignedSpan[0] = 100;
unsignedSpan[1] = 200;
unsignedSpan[2] = nuint.MaxValue;

Console.WriteLine($"\nSpan<nuint> length: {unsignedSpan.Length}");
for (int i = 0; i < unsignedSpan.Length; i++)
    Console.WriteLine($"  unsignedSpan[{i}] = {unsignedSpan[i]}");

Console.WriteLine($"\nnint size: {nint.Size} bytes");
Console.WriteLine("Success! stackalloc with nint/nuint works.");

